<template>
  <div :class="{ field: withMargin, 'is-inline': isInline }">
    <label class="label" v-if="label.length > 0">
      {{ label }}
    </label>
    <p class="control" :class="{ 'is-inline': isInline }">
      <span class="select" :class="{ 'is-top': isTop }">
        <select
          class="combobox select-input"
          :class="{
            thin,
            error,
            touched
          }"
          :style="{
            width: width ? `${width}px` : undefined
          }"
          ref="selectRef"
          :disabled="disabled"
          :required="required && !hasSelectedOption"
          @keyup.enter="emitEnter()"
          @change="updateValue"
          @blur="touched = true"
        >
          <option v-if="!hasSelectedOption" value="" disabled selected></option>
          <template
            v-for="(option, index) in options"
            :key="`${index}-${option.label}-${option.value}`"
          >
            <option
              :value="option.label || option.value"
              :selected="modelValue === option.value || null"
              :disabled="option.disabled"
            >
              {{ getOptionLabel(option) }}
            </option>
            <hr v-if="option.separator" />
          </template>
        </select>
      </span>
    </p>
  </div>
</template>

<script setup>
import { ref, computed } from 'vue'
import { useI18n } from 'vue-i18n'

const { t } = useI18n()

const props = defineProps({
  label: {
    default: '',
    type: String
  },
  modelValue: {
    default: '',
    type: [Object, String, Boolean, Number]
  },
  options: {
    default: () => [],
    type: Array
  },
  localeKeyPrefix: {
    default: '',
    type: String
  },
  isTop: {
    default: false,
    type: Boolean
  },
  disabled: {
    default: false,
    type: Boolean
  },
  error: {
    default: false,
    type: Boolean
  },
  thin: {
    default: false,
    type: Boolean
  },
  width: {
    type: Number
  },
  withMargin: {
    default: true,
    type: Boolean
  },
  isInline: {
    default: false,
    type: Boolean
  },
  required: {
    default: false,
    type: Boolean
  }
})

const emit = defineEmits(['enter', 'update:modelValue'])

const selectRef = ref(null)
const touched = ref(false)

const hasSelectedOption = computed(() => {
  return props.options.some(option => option.value === props.modelValue)
})

const isValid = computed(() => {
  return !props.required || hasSelectedOption.value
})

const updateValue = () => {
  let value = selectRef.value.value
  props.options.forEach(option => {
    if (option.label === value) {
      value = option.value
    }
  })
  emit('update:modelValue', value)
}

const emitEnter = () => {
  let value = selectRef.value.value
  props.options.forEach(option => {
    if (option.label === value) {
      value = option.value
    }
  })
  emit('enter', value)
}

const getOptionLabel = option => {
  if (props.localeKeyPrefix && option.label) {
    return t(props.localeKeyPrefix + option.label.toLowerCase())
  }
  return option.label
}

const focus = () => {
  touched.value = true
  selectRef.value?.focus()
}

defineExpose({ isValid, focus })
</script>

<style lang="scss" scoped>
.dark select:disabled {
  background: $dark-grey;
  border-color: $dark-grey-strong;
}

.is-top select {
  font-size: 1.2em;
  border: 0;
  border-bottom: 1px solid $light-grey;
  border-radius: 0;
  height: 38px;
}

.is-top select:focus {
  border-color: $green;
  outline: 0;
}

.select-input {
  height: 3em;

  &.thin {
    height: 2.1em;
  }

  &.touched:invalid {
    border-color: $red;
  }
}

.select {
  height: auto;
}
.select::after {
  border: 1px solid $green;
  border-right: 0;
  border-top: 0;
  margin-top: -4px;
}

.select.is-top::after {
  border: 2px solid $green;
  border-right: 0;
  border-top: 0;
  margin-top: -4px;
}

.error {
  border-color: $red;
}
</style>
